#include <vector>
#include <algorithm>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Sort edges by time to process them in order
    sort(edges.begin(), edges.end(), [](vector<long long> a, vector<long long> b) {
        return a[2] < b[2];
    });

    // Initialize parent array for Union-Find
    vector<long long> parent(n);
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
    }

    // Find function with path compression
    auto find = [](long long u, vector<long long>& parent) -> long long {
        if (parent[u] != u) {
            parent[u] = find(parent[u], parent);
        }
        return parent[u];
    };

    // Union function
    auto union_nodes = [](long long u, long long v, vector<long long>& parent) -> bool {
        long long root_u = find(u, parent);
        long long root_v = find(v, parent);
        if (root_u == root_v) {
            return false; // Already connected
        }
        parent[root_v] = root_u;
        return true;
    };

    // Track the number of connected components
    long long components = n;

    // Iterate through edges in order of increasing time
    for (const auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long time = edge[2];

        // Union the nodes
        if (union_nodes(u, v, parent)) {
            components--;
        }

        // Check if we have at least k components
        if (components >= k) {
            return time;
        }
    }

    // If we haven't found the answer, return the maximum time (all edges are removed)
    return edges.empty() ? 0 : edges.back()[2];
}
